// Build the Claude request. COLD, first-touch outreach to a property-tied
// call-sheet lead (Property Outreach tab, property_outreach/{id}) — NOT a
// follow-up to an existing conversation (that's workflow 17, for Leads).
// No web research (unlike workflow 13) — most of these "company" values are
// actually a person's name straight from Yardi's Tenant/Company column, so
// there's usually no real business/domain to research.
const b = $json.body || {};
const waveLabels = {
  1: 'Active pipeline (already at proposal/tour before)',
  2: 'Warm lead, 5,000+ sf requested',
  3: 'Warm lead, under 5,000 sf requested',
  4: 'Reactivation — inquired before, went dead for some reason',
  5: 'Warm lead, size unknown — never qualified'
};
const waveLabel = waveLabels[Number(b.wave)] || 'unknown';

const sizeLine = b.sqft ? (Number(b.sqft).toLocaleString() + ' sf' + (b.sqft_est ? ' (estimated)' : '')) : 'not on file — ask what they need';

const DEFAULT_SYS = 'You are drafting a short, first-touch COLD outreach email from Justin Cho at Cubework to a lead pulled from a property call sheet (Yardi). This is cold outreach, not a follow-up to an existing conversation. Cubework offers flexible month-to-month warehouse, office, and dock space with simple license agreements (never a lease), all-inclusive pricing (one flat monthly rate, no NNN, no CAM, no surprise utility bills), and fast move-in (24-48 hours).\n\nYou will be given basic lead details from the call sheet, and CURRENT TALKING POINTS Justin is typing in right now.\n\nIMPORTANT ABOUT THE COMPANY FIELD: it comes straight from a Yardi tenant/inquiry list and is very often a person\'s own name (for example Jessie Chen) rather than a real business name (for example Acme Logistics Inc). If it reads like a person\'s name, greet them by first name. If it clearly reads like a business name, do not invent a contact name, greet them generically or reference the business itself.\n\nIMPORTANT ABOUT CALL SHEET NOTES: the source notes field is historical Yardi and CRM data, deal stage, past call outcomes, dead-deal reasons. It reflects what was true when it was recorded, not necessarily now. Treat it as background only. Do not state or imply current availability, current pricing, or a live status unless the CURRENT TALKING POINTS section below confirms it. If you reference something from the source notes, frame it as already on file, for example we spoke with you before about space here, never as a current fact.\n\nCURRENT TALKING POINTS ARE DIFFERENT: those ARE current and verified as of today. State them plainly and confidently when given, for example a specific available size range or a live discount. If none are given, do not invent one, just lead with the core value pitch instead.\n\nWrite ONE cold outreach email that: 1) Opens with a brief, warm, honest reason for reaching out, something that reads like a real person glad to check back in, not a stiff opener. If the call wave says this is a reactivation, it is fine to acknowledge they looked into space here before, without inventing the specific reason it went dead. 2) States the current talking points naturally if given, this is the main hook. If none are given, lead with the core value pitch instead, month-to-month, all-inclusive, fast move-in. 3) If a CUBEWORK LINK is given below, work that exact link into the body once, naturally, so they can see photos and details, for example something like you can see it here colon then the link. Never shorten, alter, or invent a link. If no link is given, do not mention one or make one up. 4) Ends with ONE short, friendly, low-friction question asking whether they are still looking for space or still in the market, NOT an invitation to tour or take a look at a unit. If the size on file is unknown, fold that into the same question, for example still looking, and if so what size space do you need. 5) Signs off on its own line, exactly: Best,\nJustin Cho\nBusiness Development, Cubework\n\nVOICE: friendly, warm, plain, direct, like a real person glad to reach out, never like a template or a marketing email. A little genuine warmth in the opening or closing line is good, as long as it stays short and natural. Short sentences, most under 12 words, one idea each. Write at a 5th-grade reading level. Use the simplest word that works. No jargon. Never use any of these: I hope this email finds you well, I wanted to reach out, my name is, I came across your, to whom it may concern, per my last email, just checking in, circling back, leverage, synergy, streamline, elevate, solutions, ideal for, I would be happy to discuss. Do not use any dash character to join clauses, no em dash, no en dash, no double hyphen, use a period or comma instead. No bulleted or numbered lists. No hype, no exclamation points. NEVER use the word lease in any form, say no long-term commitment instead. Keep the email body under 90 words, not counting the sign-off or the link if one is included.\n\nSUBJECT: 3 to 6 words, lowercase or sentence case, references the property or the current talking point when possible, for example space now open at ontario airport. Never generic like warehouse space available.\n\nReturn ONLY minified JSON, no prose, no code fences: {"subject":"...","body":"..."}';

// Per-property prompt override (added 2026-07-09, A/B testing feature): the app lets
// Justin save a custom name + full system prompt per property (property_outreach_context
// docs, passed through in the webhook body) so different properties can run differently
// toned drafts and be compared over time. Falls back to DEFAULT_SYS untouched when a
// property has not set one.
const sys = b.system_prompt || DEFAULT_SYS;

const userMsg = 'LEAD DETAILS (from a Yardi call sheet)\n' +
  'Company / contact name (see note above about this sometimes being a person): ' + (b.company || '(unknown)') + '\n' +
  'Property: ' + (b.locationName || b.location || '(unknown)') + '\n' +
  'Call wave: ' + (b.wave != null ? b.wave : '(none)') + ' — ' + waveLabel + '\n' +
  'Requested size on file: ' + sizeLine + '\n\n' +
  'CALL SHEET BACKGROUND (historical, not necessarily current — see honesty rule above):\n' + (b.source_notes || '(none on file)') + '\n\n' +
  'CURRENT TALKING POINTS (fresh, verified as of today):\n' +
  'Available space: ' + (b.available_space || '(none given)') + '\n' +
  'Pricing / discount: ' + (b.discount || '(none given)') + '\n' +
  'Other: ' + (b.other || '(none given)') + '\n' +
  'Cubework link: ' + (b.cubework_url || '(none given, do not mention or invent a link)');

const requestBody = {
  model: 'claude-sonnet-4-6',
  max_tokens: 700,
  system: sys,
  messages: [ { role: 'user', content: userMsg } ]
};
return [{ json: { id: b.id, available_space: b.available_space || '', discount: b.discount || '', other: b.other || '', cubework_url: b.cubework_url || '', prompt_name: b.prompt_name || '', system_prompt_used: sys, requestBody } }];

const ctx = $('Build Claude request').item.json;
let parsed = {};
try {
  const blocks = $json.content || [];
  const raw = Array.isArray(blocks) ? blocks.filter(x => x && x.type === 'text').map(x => x.text).join('\n') : '';
  const m = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(m ? m[0] : raw);
} catch (e) { parsed = {}; }
const dedash = s => String(s == null ? '' : s).replace(/\s*[\u2014\u2013]\s*/g, ', ').replace(/\s--\s/g, ', ');
const now = new Date().toISOString();
const S = v => ({ stringValue: (v == null ? '' : String(v)) });
const subject = dedash(parsed.subject || '');
const body = dedash(parsed.body || '');
const fields = {
  cold_draft: { mapValue: { fields: {
    subject: S(subject),
    body: S(body),
    generated_at: S(now),
    prompt_name: S(ctx.prompt_name),
    system_prompt_used: S(ctx.system_prompt_used)
  } } },
  draft_context: { mapValue: { fields: {
    available_space: S(ctx.available_space),
    discount: S(ctx.discount),
    other: S(ctx.other),
    cubework_url: S(ctx.cubework_url)
  } } }
};
return [{ json: { id: ctx.id, fsBody: { fields } } }];
